import importlib.util,hmac,hashlib,base64,json; spec = importlib.util.spec_from_file_location('m','/tmp/eval_jwt/jwt.py'); mod = importlib.util.module_from_spec(spec); spec.loader.exec_module(mod); payload = {'user_id': 42, 'role': 'admin'}; tok = mod.jwt_encode(payload, 'secret'); assert mod.jwt_decode(tok, 'secret') == payload
parts = tok.split('.'); assert len(parts) == 3, f'not 3 segments: {tok}'; assert '=' not in tok, 'padding present'
signing_input = (parts[0] + '.' + parts[1]).encode(); expected_sig = base64.urlsafe_b64encode(hmac.new(b'secret', signing_input, hashlib.sha256).digest()).rstrip(b'=').decode(); assert hmac.compare_digest(parts[2], expected_sig), f'signature is not HMAC-SHA256 over header.payload: {parts[2]} vs {expected_sig}'
def b64d(s): return base64.urlsafe_b64decode(s + '=' * (-len(s) % 4)); assert json.loads(b64d(parts[1])) == payload, 'payload segment does not decode to payload'
try: mod.jwt_decode(tok, 'wrong')
except ValueError: pass
else: raise AssertionError('bad signature accepted')
tok2 = mod.jwt_encode({'user_id':1,'exp':100}, 'secret')
try: mod.jwt_decode(tok2, 'secret', now=200)
except ValueError: pass
else: raise AssertionError('expired token accepted')
assert mod.jwt_decode(tok2, 'secret', now=50) == {'user_id':1,'exp':100}, 'unexpired exp token rejected'
try: mod.jwt_decode('not.a.jwt.token', 'secret')
except ValueError: pass
else: raise AssertionError('malformed token accepted')
print('OK')
